    return new, new != text

def strip_precompute_injections(text):
    changed = False
    markers = [
        "// Pre-compute legacy costs for selected uniform operations that VPlan may",
        "// Pre-charge legacy costs for uniform intrinsic @llvm.smax.* and urem",
        "// Pre-compute the cost for certain uniform intrinsics that VPlan may widen,"
    ]
    for marker in markers:
        while True:
            pos = text.find(marker)
            if pos == -1:
                break
            loop_start = text.find("for (BasicBlock *BB", pos)
            if loop_start == -1:
                # remove the marker line only
                text = text[:pos] + text[pos+len(marker):]
                changed = True
                break
            depth = 0
            end = None
            for i in range(loop_start, len(text)):
